const xml = $json.data || '';

function extractTag(str, tag) {
  const match = str.match(new RegExp(`<${tag}(?:[^>]*)>([\\s\\S]*?)<\\/${tag}>`, 'i'));
  return match ? match[1].replace(/<!\[CDATA\[([\\s\\S]*?)\]\]>/g, '$1').trim() : '';
}

function extractAllTags(str, tag) {
  const results = [];
  const regex = new RegExp(`<${tag}(?:[^>]*)>([\\s\\S]*?)<\\/${tag}>`, 'gi');
  let match;
  while ((match = regex.exec(str)) !== null) {
    results.push(match[1].replace(/<!\[CDATA\[([\\s\\S]*?)\]\]>/g, '$1').trim());
  }
  return results;
}

const itemRegex = /<item>([\s\S]*?)<\/item>/gi;
const items = [];
let m;
while ((m = itemRegex.exec(xml)) !== null) {
  const block = m[1];
  const link = extractTag(block, 'link') || extractTag(block, 'guid');
  const title = extractTag(block, 'title');
  const pubDate = extractTag(block, 'pubDate');
  const description = extractTag(block, 'description');
  const category = extractAllTags(block, 'category').join(', ');

  if (!title && !link) continue;

  items.push({
    json: {
      title,
      link,
      pubDate,
      text: description.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim(),
      category
    }
  });
}

if (!items.length) {
  throw new Error('WTO RSS: nessun item trovato nel feed XML');
}

return items;

function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'daily');

return [{
  json: {
    source: 'WTO_NEWS',
    source_url: meta.url || original.link || null,
    country: 'BR',
    macroarea: 'geo',
    collected_at: now,
    collected_period: _collectedPeriod,
        url: meta.url,
    topic: meta.topic,
    relevance_score: meta.relevance_score,
    reason: meta.reason,
    title: original.title,
    pubDate: original.pubDate,
    signals: signals.signals,
    entities: signals.entities,
    sentiment: signals.sentiment,
    summary_en: signals.summary_en,
    embed_text: signals.summary_en + ' ' + (signals.signals || []).join('. ')
  }
}];

// Calcola collected_period da collected_at + cadenza
function getCollectedPeriod(collectedAt, cadenza) {
  const d = new Date(collectedAt || new Date().toISOString());
  const pad = (n) => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  // ISO week number
  const startOfYear = new Date(Date.UTC(yyyy, 0, 1));
  const weekNo = pad(Math.ceil(((d - startOfYear) / 86400000 + startOfYear.getUTCDay() + 1) / 7));
  switch((cadenza || '').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${weekNo}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}

const _cadenza = 'daily';
const _collectedAt = now || new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(_collectedAt, _cadenza);
const meta = $('WTO Parse Signals').item.json;
const vector = $json.data[0].embedding;

const url = meta.url;
let hash = 0;
for (let i = 0; i < url.length; i++) {
  hash = ((hash << 5) - hash) + url.charCodeAt(i);
  hash |= 0;
}
const pointId = Math.abs(hash);

return [{
  json: {
    points: [{
      id: pointId,
      vector: vector,
      payload: {
        country: meta.country,
        macroarea: meta.macroarea,
        collected_at: meta.collected_at,
        url: meta.url,
        topic: meta.topic,
        relevance_score: meta.relevance_score,
        sentiment: meta.sentiment,
        summary_en: meta.summary_en,
        signals: meta.signals
      }
    }]
  }
}];

const now = new Date().toISOString();
const meta = $('WTO Parse Signals').item.json;

return [{
  json: {
    source: 'WTO_RSS',
    country: 'BR',
    macroarea: 'geo',
    cadenza: '6h',
    run_date: now,
    status: 'done',
    completed_at: now,
    items_ingested: meta.items_count || null,
  },
}];

const html = $json.data || '';
const meta = $('WTO Parse Filter').item.json;

const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 6000);

return [{
  json: {
    ...meta,
    article_text: text
  }
}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '12_WTO_NEWS',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
